/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `player_ability` (
  `player_id` int(10) unsigned NOT NULL COMMENT 'Foreign key to “player” table',
  `ability_id` int(10) unsigned NOT NULL COMMENT 'Foreign key to “ability” table',
  `score` smallint(5) unsigned NOT NULL DEFAULT 10 COMMENT 'Ability score',
  `bonus` smallint(5) unsigned NOT NULL DEFAULT 0 COMMENT 'Ability bonus',
  `modifier` smallint(6) NOT NULL DEFAULT 0 COMMENT 'Modifier',
  `is_primary_ability` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'The ability is the player''s primary one',
