DROP TABLE IF EXISTS `weapon`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `weapon` (
  `item_id` int(10) unsigned NOT NULL COMMENT 'Primary key synchronized 1:1 with the “item” table',
  `amunition_id` int(10) unsigned DEFAULT NULL COMMENT 'Optional foreign key to weapon ammunition item. Used only when the “need_amunition” flag is set to TRUE.',
  `damage_type_id` int(10) unsigned DEFAULT NULL COMMENT 'Optional foreign key to “damage_type” table',
  `damage_dice` varchar(8) CHARACTER SET utf8mb3 COLLATE utf8mb3_bin DEFAULT NULL COMMENT 'Roll dice to determine damage',
  `is_melee` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Indicates a melee weapon. A melee weapon is used to attack a target within 5 feet of you',
  `is_ranged` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Indicates a ranged weapon. A ranged weapon is used to attack a target at a distance',
  `is_simple` tinyint(1) NOT NULL DEFAULT 1 COMMENT 'Indicates a simple weapon. Most people can use simple weapons with proficiency',
  `is_martial` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Indicates a martial weapon. Most warriors use martial weapons because these weapons put their fighting style and training to best use',
  `need_ammunition` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Flag indicating that the weapon requires ammunition for use',
  `is_finesse` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'When making an attack with a finesse weapon, you use your choice of your Strength or Dexterity modifier for the attack and damage rolls. You must use the same modifier for both rolls',
  `is_heavy` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Small creatures have disadvantage on attack rolls with heavy weapons. A heavy weapon’s size and bulk make it too large for a Small creature to use effectively',
  `is_light` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'A light weapon is small and easy to handle, making it ideal for use when fighting with two weapons.',
  `is_loading` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'Because of the time required to load this weapon, you can fire only one piece of ammunition from it when you use an action, bonus action, or reaction to fire it, regardless of the number of attacks you can normally make',
  `is_range` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'A weapon that can be used to make a ranged attack has a range in parentheses after the ammunition or thrown property. The range lists two numbers. The first is the weapon’s normal range in feet, and the second indicates the weapon’s long range. When attacking a target beyond normal range, you have disadvantage on the attack roll. You can’t attack a target beyond the weapon’s long range',
  `range_min` smallint(5) unsigned DEFAULT NULL COMMENT 'Minimum range',
  `range_max` smallint(5) unsigned DEFAULT NULL COMMENT 'Maximum range',
  `is_reach` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'This weapon adds 5 feet to your reach when you attack with it, as well as when determining your reach for opportunity attacks with it',
  `is_special` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'A weapon with the special property has unusual rules governing its use, explained in the weapon’s description',
  `is_thrown` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'If a weapon has the thrown property, you can throw the weapon to make a ranged attack. If the weapon is a melee weapon, you use the same ability modifier for that attack roll and damage roll that you would use for a melee attack with the weapon. For example, if you throw a handaxe, you use your Strength, but if you throw a dagger, you can use either your Strength or your Dexterity, since the dagger has the finesse property',
  `is_two_handed` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'This weapon requires two hands when you attack with it',
  `is_versatile` tinyint(1) NOT NULL DEFAULT 0 COMMENT 'This weapon can be used with one or two hands',
  `versatile_dice` varchar(8) DEFAULT NULL COMMENT 'Roll dice to determine the damage when the weapon is used with two hands to make a melee attack',
  PRIMARY KEY (`item_id`),
  KEY `fk_item` (`item_id`),
  KEY `fk_amunition` (`amunition_id`),
  KEY `fk_damage_type` (`damage_type_id`),
  CONSTRAINT `weapon_ibfk_1` FOREIGN KEY (`item_id`) REFERENCES `item` (`id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `weapon_ibfk_2` FOREIGN KEY (`amunition_id`) REFERENCES `item` (`id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `weapon_ibfk_3` FOREIGN KEY (`damage_type_id`) REFERENCES `damage_type` (`id`) ON DELETE SET NULL ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci COMMENT='Your class grants proficiency in certain weapons, reflecting both the class’s focus and the tools you are most likely to use. Whether you favor a longsword or a longbow, your weapon and your ability to wield it effectively can mean the difference between life and death while adventuring. The Weapons table shows the most common weapons used in the fantasy gaming worlds, their price and weight, the damage they deal when they hit, and any special properties they possess.';
